          __m512d Ri=_mm512_fmadd_pd(KP623,ai,_mm512_fnmadd_pd(KP222,bi,t1i));
          __m512d Sre=_mm512_fmadd_pd(KP433,fi,_mm512_fmadd_pd(KP974,ei,_mm512_mul_pd(KP781,di)));
